import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { specReferencesRule } from "./spec-references.rule.js";

describe("spec-references rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, specReferencesRule, "@a10n/blueprint-typespec");
  });

  const FEATURE_WITH_INV = `
    @feature
    namespace Products.MyProduct.Features.Lifecycle {
      @invariant(#{
        predicate: "A task has an id.",
        why: "Reason.",
      })
      op task_has_id(): void;
    }
  `;

  const COMPONENT_HEADER = `
    @component(#{ type: ComponentType.Service })
    namespace Components.MyApiService {
  `;

  const COMPONENT_FOOTER = `
    }
  `;

  // T012_05: {@Actor} in prose — zero diagnostics
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_spec_references
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T012.T012_05
  it("T012_05: {@Actor} in prose — no diagnostic", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("{@Actor} submits the form")
          @flow
          op T001_05(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_06: actor_ref — not deterministically implementable (linguistic).
  // bare 'User' in prose does not fire any diagnostic from this rule.
  it("T012_06: bare 'User' in prose — spec-references rule is silent (actor detection is linguistic)", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("User submits the form")
          @flow
          op T001_06(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_07: "HTTP 200" (not wrapped) in prose — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T012.T012_07
  it("T012_07: bare HTTP 200 text in prose — no diagnostic", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("Returns HTTP 200 OK")
          @flow
          op T001_07(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_08: {@HTTP} in prose — spec-references rule does NOT fire (no_std_ref is covered
  // by inline-refs rule's unresolved-inline-ref warning, not this rule).
  it("T012_08: {@HTTP} in prose — spec-references rule is silent (inline-refs handles it)", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("{@HTTP} 200 OK")
          @flow
          op T001_08(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_09: "the system validates" (not wrapped) in prose — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T012.T012_09
  it("T012_09: bare 'system' text (not wrapped) in prose — no diagnostic", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("the system validates the request body")
          @flow
          op T001_09(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_10: {@system} in prose — spec-references rule is silent (inline-refs handles it
  // via unresolved-inline-ref if "system" is not a declared construct).
  it("T012_10: {@system} in prose — spec-references rule is silent (inline-refs handles it)", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("{@system} validates the request")
          @flow
          op T001_10(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_01–T012_04: TODO: requires full program analysis (using declarations and bare names)
  it("T012_01: compile fixture without bare-name assertions — no crash (TODO: full analysis)", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("POST /tasks")
          @flow
          op T001_01(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

  // T012_11–T012_16: TODO: requires full program analysis (using declarations)
  it("T012_11: compile fixture with no using-related assertions — no crash (TODO: full analysis)", async () => {
    await ruleTester
      .expect(`
        ${FEATURE_WITH_INV}
        ${COMPONENT_HEADER}
          @doc("POST /tasks with valid body")
          @flow
          op T001_11(): void;
        ${COMPONENT_FOOTER}
      `)
      .toBeValid();
  });

});
